   type Number is range <>;
package Strings_Edit.Integer_Edit

subprograms.code:
procedure Get
          (  Source  : in String;
             Pointer : in out Integer;
             Value   : out Number'Base;
             Base    : in NumberBase := 10;
             First   : in Number'Base := Number'First;
             Last    : in Number'Base := Number'Last;
             ToFirst : in Boolean := False;
             ToLast  : in Boolean := False
          )

function Image
         (  Value   : in Number'Base;
            Base    : in NumberBase := 10;
            PutPlus : in Boolean := False
         )  return String

procedure Put
          (  Destination : in out String;
             Pointer     : in out Integer;
             Value       : in Number'Base;
             Base        : in NumberBase := 10;
             PutPlus     : in Boolean := False;
             Field       : in Natural := 0;
             Justify     : in Alignment := Left;
             Fill        : in Character := ' '
          )

function Value
         (  Source  : in String;
            Base    : in NumberBase := 10;
            First   : in Number'Base := Number'First;
            Last    : in Number'Base := Number'Last;
            ToFirst : in Boolean := False;
            ToLast  : in Boolean := False
         )  return Number'Base
